import { useState, useEffect } from 'react';
import '../index.css';
import { useNavigate } from 'react-router-dom';

export function NavBar() {
  const navigate = useNavigate();
  const [userEmail, setUserEmail] = useState("");

  // Funkcija za čitanje cookie-a po imenu
  const getCookie = (name) => {
    const match = document.cookie.match(new RegExp('(^| )' + name + '=([^;]+)'));
    if (match) return decodeURIComponent(match[2]);
    return null;
  };

  // Proverava cookie kada se NavBar učita
  useEffect(() => {
    const email = getCookie("userEmail"); // ime cookie-a koji čuvaš pri login-u
    if (email) {
      setUserEmail(email);
    }
  }, []);

  const handleLogout = () => {
    document.cookie = "userEmail=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;";
    document.cookie = "userId=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;";
    setUserEmail("");
    navigate("/");
  };

  // Proverava da li je gost ulogovan
  const userId = getCookie("userId");

  return (
    <header>
      <nav
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          width: "100%",
          boxSizing: "border-box",
          background: "#af65c5",
          padding: "20px"
        }}
      >
        {/* Levi deo - pretraga */}
        <div style={{ flex: 1, display: "flex", justifyContent: "center" }}>
          <input
            type="text"
            style={{
              width: "60%",
              height: "25px",
              fontSize: "18px",
              borderRadius: "8px",
              padding: "5px 10px",
            }}
          />
        </div>

        {/* Desni deo - dugmad i email */}
        <div style={{ display: "flex", gap: "10px", alignItems: "center" }}>
          {userId && (
            <span
              className="btnNav"
              style={{ cursor: "pointer" }}
              onClick={() => navigate("/rezervacije")}
            >
              Rezervacije
            </span>
          )}

          {userEmail ? (
            <>
              <span style={{ color: "white", fontSize: "16px" }}>
                {userEmail}
              </span>
              <span className="btnNav" onClick={handleLogout}>Logout</span>
            </>
          ) : (
            <>
              <span className="btnNav" onClick={() => { navigate("/registracija"); }}>Register</span>
              <span className="btnNav" onClick={() => { navigate("/login"); }}>Login</span>
            </>
          )}
        </div>
      </nav>
    </header>
  );
}
